/**
 * Graph construction from NavGraph JSON.
 *
 * Builds a typed ngraph.graph instance from a serialized NavGraph object,
 * handling bidirectional edge expansion and cross-floor edge synthesis.
 * Also exports a Euclidean distance utility used for edge weight calculation
 * and A* heuristic.
 */

import type { NavEdge, NavEdgeData, NavGraph, NavNode, NavNodeData } from '@shared/types'
import type { Graph } from 'ngraph.graph'
import createGraph from 'ngraph.graph'

/**
 * Flattens a multi-floor NavGraph into a single list of nodes and edges.
 *
 * Retained for the admin map editor (MapEditorCanvas.tsx) which depends on
 * this function to flatten the NavGraph before editing and re-wrap it on save.
 * This function is NOT called inside buildGraph as of Phase 17.
 */
export function flattenNavGraph(navGraph: NavGraph): { nodes: NavNode[]; edges: NavEdge[] } {
  const nodes: NavNode[] = []
  const edges: NavEdge[] = []
  for (const building of navGraph.buildings) {
    for (const floor of building.floors) {
      nodes.push(...floor.nodes)
      edges.push(...floor.edges)
    }
  }
  return { nodes, edges }
}

/**
 * Constructs a live ngraph.graph from a serialized NavGraph JSON object.
 *
 * Phase 17 implementation: iterates buildings → floors directly (no longer
 * calls flattenNavGraph internally). After all nodes and intra-floor edges
 * are added, performs a second pass to synthesize bidirectional inter-floor
 * edges from connectsToNodeAboveId on stairs, elevator, and ramp nodes.
 *
 * Inter-floor edge weights:
 * - stairs: standardWeight=0.3, accessibleWeight=Infinity, accessible=false
 * - elevator/ramp: standardWeight=0.3, accessibleWeight=0.45, accessible=true
 *
 * For each node: destructures `{ id, ...data }` and adds to graph.
 * For each intra-floor edge: adds a directed link. If `bidirectional` is true,
 * also adds the reverse directed link so both `graph.getLink(a, b)`
 * and `graph.getLink(b, a)` return a link.
 *
 * The pathfinding engine uses x, y, and weight fields for routing; extra
 * fields (floorId, connector IDs) are stored as node data and passed through.
 */
export function buildGraph(navGraph: NavGraph): Graph<NavNodeData, NavEdgeData> {
  const graph = createGraph<NavNodeData, NavEdgeData>()

  // Pass 1: add all nodes and intra-floor edges from all buildings and floors.
  for (const building of navGraph.buildings) {
    for (const floor of building.floors) {
      for (const { id, ...data } of floor.nodes) {
        graph.addNode(id, data)
      }

      for (const { id: _id, sourceId, targetId, ...data } of floor.edges) {
        // Normalize accessibleWeight to Infinity for non-accessible edges.
        // JSON cannot represent Infinity, so the serialized form uses a large
        // finite number. The graph should carry the true semantic value.
        const edgeData: NavEdgeData = data.accessible
          ? data
          : { ...data, accessibleWeight: Number.POSITIVE_INFINITY }
        graph.addLink(sourceId, targetId, edgeData)
        if (edgeData.bidirectional) {
          graph.addLink(targetId, sourceId, edgeData)
        }
      }
    }
  }

  // Pass 2: synthesize bidirectional inter-floor edges from connector nodes.
  // Only process connectsToNodeAboveId to avoid adding each pair twice
  // (the counterpart node on the floor above has connectsToNodeBelowId pointing
  // back, which would duplicate the edge if we processed both directions here).
  const processedPairs = new Set<string>()

  graph.forEachNode((node) => {
    const data = node.data
    const nodeType = data.type

    if (
      (nodeType === 'stairs' || nodeType === 'elevator' || nodeType === 'ramp') &&
      data.connectsToNodeAboveId != null
    ) {
      const targetId = data.connectsToNodeAboveId
      if (!graph.hasNode(targetId)) return

      // Build a canonical pair key (sorted) to skip duplicates.
      const pairKey = [node.id, targetId].sort().join('|')
      if (processedPairs.has(pairKey)) return
      processedPairs.add(pairKey)

      // Skip if links already exist (e.g. JSON stored inter-floor edges).
      if (graph.hasLink(node.id, targetId) || graph.hasLink(targetId, node.id)) return

      const isAccessible = nodeType === 'elevator' || nodeType === 'ramp'
      const interFloorEdge: NavEdgeData = {
        standardWeight: 0.3,
        accessibleWeight: isAccessible ? 0.45 : Number.POSITIVE_INFINITY,
        accessible: isAccessible,
        bidirectional: true,
      }

      graph.addLink(node.id, targetId, interFloorEdge)
      graph.addLink(targetId, node.id, interFloorEdge)
    }
  })

  return graph
}

/**
 * Computes Euclidean distance between two points.
 *
 * Used by:
 * - Admin editor (Phase 9) to auto-compute edge weights from node coordinates
 * - Pathfinding engine (Plan 02) as the A* heuristic function
 *
 * @param ax - X coordinate of point A
 * @param ay - Y coordinate of point A
 * @param bx - X coordinate of point B
 * @param by - Y coordinate of point B
 * @returns Euclidean distance between the two points
 */
export function calculateWeight(ax: number, ay: number, bx: number, by: number): number {
  return Math.sqrt((ax - bx) ** 2 + (ay - by) ** 2)
}

import useImage from 'use-image'

/**
 * Target for floor plan image loading.
 * - `{ buildingId, floorNumber }` — load a specific building floor image
 * - `'campus'` — load the campus overhead image
 * - `undefined` (legacy) — load via thumbnail + full progressive path
 */
type FloorTarget = { buildingId: number; floorNumber: number } | 'campus'

/**
 * Progressive floor plan image loading with optional multi-floor target support.
 *
 * @param target - Optional target for the image to load:
 *   - `{ buildingId, floorNumber }`: loads `/api/floor-plan/{buildingId}/{floorNumber}`
 *   - `'campus'`: loads `/api/campus/image`
 *   - `undefined` (legacy): progressive thumbnail + full image for `/api/floor-plan/thumbnail` and `/api/floor-plan/image`
 *
 * All `useImage` hooks are called unconditionally (React rules of hooks).
 * Unused slots receive `''` (empty string) — `useImage('')` does not fetch.
 *
 * Returns shape unchanged: `{ image, isLoading, isFailed, isFullLoaded }`
 */
export function useFloorPlanImage(target?: FloorTarget) {
  // Multi-floor target URL (campus or specific floor)
  const targetUrl =
    target === 'campus'
      ? '/api/campus/image'
      : target
        ? `/api/floor-plan/${target.buildingId}/${target.floorNumber}`
        : ''

  // Legacy thumbnail URL — only used when target is undefined
  const thumbUrl = target ? '' : '/api/floor-plan/thumbnail'
  // Legacy full URL — only used when target is undefined
  const fullUrl = target ? '' : '/api/floor-plan/image'

  const [targetImg, targetStatus] = useImage(targetUrl)
  const [thumb, thumbStatus] = useImage(thumbUrl)
  const [full, fullStatus] = useImage(fullUrl)

  if (target) {
    // Multi-floor mode: single image, no progressive loading
    return {
      /** Single image for the specified floor or campus view */
      image: targetStatus === 'loaded' ? targetImg : undefined,
      /** True while the target image is loading */
      isLoading: targetStatus === 'loading',
      /** True if the target image failed to load */
      isFailed: targetStatus === 'failed',
      /** True once the target image has loaded */
      isFullLoaded: targetStatus === 'loaded',
    }
  }

  // Legacy mode: progressive thumbnail + full
  return {
    /** Best available image: full-res if loaded, else thumbnail, else undefined */
    image: fullStatus === 'loaded' ? full : thumbStatus === 'loaded' ? thumb : undefined,
    /** True while neither thumbnail nor full image has loaded yet */
    isLoading: thumbStatus === 'loading' && fullStatus !== 'loaded',
    /** True only when both thumbnail and full image failed to load */
    isFailed: thumbStatus === 'failed' && fullStatus === 'failed',
    /** True once the full-resolution image has loaded */
    isFullLoaded: fullStatus === 'loaded',
  }
}

import * as bcrypt from 'bcryptjs'
import { Hono } from 'hono'
import { deleteCookie, setCookie } from 'hono/cookie'
import { jwt, sign } from 'hono/jwt'
import { ADMIN_EMAIL, ADMIN_PASSWORD_HASH, JWT_SECRET } from './credentials'
import { loginLimiter } from './loginLimiter'

/** Placeholder hash used when ADMIN_PASSWORD_HASH is not set — prevents timing attacks */
const PLACEHOLDER_HASH = '$2b$12$invalid.hash.placeholder.value.xx'

export const authRoutes = new Hono()

/**
 * POST /login
 * Validates admin credentials and issues a JWT in an httpOnly cookie.
 * Rate-limited to 5 attempts per 10-minute window per IP.
 */
authRoutes.post('/login', loginLimiter, async (c) => {
  const body = (await c.req.json().catch(() => ({}))) as Record<string, unknown>
  const email = typeof body.email === 'string' ? body.email : ''
  const password = typeof body.password === 'string' ? body.password : ''

  const emailMatch = email === ADMIN_EMAIL

  // Always run bcrypt.compare to prevent timing attacks, even when email doesn't match
  const hashToCompare = ADMIN_PASSWORD_HASH || PLACEHOLDER_HASH
  const passMatch = await bcrypt.compare(password, hashToCompare)

  if (!emailMatch || !passMatch) {
    return c.json({ error: 'Invalid credentials' }, 401)
  }

  const token = await sign(
    {
      sub: ADMIN_EMAIL,
      role: 'admin',
      exp: Math.floor(Date.now() / 1000) + 7200,
    },
    JWT_SECRET,
    'HS256',
  )

  setCookie(c, 'admin_token', token, {
    httpOnly: true,
    secure: process.env.NODE_ENV === 'production',
    sameSite: 'Lax',
    path: '/',
    maxAge: 7200,
  })

  return c.json({ ok: true }, 200)
})

/**
 * POST /logout
 * Clears the admin_token cookie server-side.
 */
authRoutes.post('/logout', (c) => {
  deleteCookie(c, 'admin_token', { path: '/' })
  return c.json({ ok: true })
})

/**
 * GET /me
 * Returns auth status for the current session.
 * Protected by JWT middleware — requires valid admin_token cookie.
 */
authRoutes.get('/me', jwt({ secret: JWT_SECRET, alg: 'HS256', cookie: 'admin_token' }), (c) => {
  return c.json({ authenticated: true })
})

import type { NavEdge, NavNode } from '@shared/types'
import { useReducer, useRef, useState } from 'react'

// ============================================================
// Types
// ============================================================

export type EditorMode = 'select' | 'add-node' | 'add-edge'

export type EditorState = {
  nodes: NavNode[]
  edges: NavEdge[]
  mode: EditorMode
  selectedNodeId: string | null
  selectedEdgeId: string | null
  pendingEdgeSourceId: string | null
  isDirty: boolean
  // Multi-floor context (added Phase 18)
  activeBuildingId: number | 'campus'
  activeFloorId: number | null  // null when campus is active
  floorSnapshots: Record<number, { nodes: NavNode[]; edges: NavEdge[] }>
  campusSnapshot: { nodes: NavNode[]; edges: NavEdge[] } | null
}

export type EditorAction =
  | { type: 'LOAD_GRAPH'; nodes: NavNode[]; edges: NavEdge[] }
  | { type: 'SET_MODE'; mode: EditorMode }
  | { type: 'PLACE_NODE'; node: NavNode }
  | { type: 'MOVE_NODE'; id: string; x: number; y: number }
  | { type: 'UPDATE_NODE'; id: string; changes: Partial<NavNode> }
  | { type: 'REPLACE_NODES'; nodes: NavNode[]; isDirty: boolean }
  | { type: 'SELECT_NODE'; id: string | null }
  | { type: 'SET_PENDING_EDGE_SOURCE'; id: string | null }
  | { type: 'CREATE_EDGE'; edge: NavEdge }
  | { type: 'UPDATE_EDGE'; id: string; changes: Partial<NavEdge> }
  | { type: 'SELECT_EDGE'; id: string | null }
  | { type: 'DELETE_NODE'; id: string }
  | { type: 'DELETE_EDGE'; id: string }
  | { type: 'MARK_SAVED' }
  | { type: 'RESTORE_SNAPSHOT'; snapshot: EditorState }
  | { type: 'SWITCH_FLOOR'; floorId: number; nodes: NavNode[]; edges: NavEdge[] }
  | { type: 'SWITCH_TO_CAMPUS'; nodes: NavNode[]; edges: NavEdge[] }
  | { type: 'SWITCH_BUILDING'; buildingId: number | 'campus' }

// ============================================================
// Initial State
// ============================================================

const initialState: EditorState = {
  nodes: [],
  edges: [],
  mode: 'select',
  selectedNodeId: null,
  selectedEdgeId: null,
  pendingEdgeSourceId: null,
  isDirty: false,
  activeBuildingId: 1,        // Default to building 1 (Main Building)
  activeFloorId: null,        // null until first floor is loaded
  floorSnapshots: {},
  campusSnapshot: null,
}

// ============================================================
// Reducer
// ============================================================

function editorReducer(state: EditorState, action: EditorAction): EditorState {
  switch (action.type) {
    case 'LOAD_GRAPH':
      return {
        ...state,
        nodes: action.nodes,
        edges: action.edges,
        isDirty: false,
        selectedNodeId: null,
        selectedEdgeId: null,
        pendingEdgeSourceId: null,
      }

    case 'SET_MODE':
      return {
        ...state,
        mode: action.mode,
        selectedNodeId: null,
        selectedEdgeId: null,
        pendingEdgeSourceId: null,
      }

    case 'PLACE_NODE':
      return {
        ...state,
        nodes: [...state.nodes, action.node],
        isDirty: true,
      }

    case 'MOVE_NODE':
      return {
        ...state,
        nodes: state.nodes.map((n) =>
          n.id === action.id ? { ...n, x: action.x, y: action.y } : n,
        ),
        isDirty: true,
      }

    case 'UPDATE_NODE':
      return {
        ...state,
        nodes: state.nodes.map((n) => (n.id === action.id ? { ...n, ...action.changes } : n)),
        isDirty: true,
      }

    case 'REPLACE_NODES':
      return {
        ...state,
        nodes: action.nodes,
        selectedNodeId: action.nodes.some((node) => node.id === state.selectedNodeId)
          ? state.selectedNodeId
          : null,
        isDirty: action.isDirty,
      }

    case 'SELECT_NODE':
      return {
        ...state,
        selectedNodeId: action.id,
        selectedEdgeId: null,
      }

    case 'SET_PENDING_EDGE_SOURCE':
      return {
        ...state,
        pendingEdgeSourceId: action.id,
      }

    case 'CREATE_EDGE':
      return {
        ...state,
        edges: [...state.edges, action.edge],
        pendingEdgeSourceId: null,
        isDirty: true,
      }

    case 'UPDATE_EDGE':
      return {
        ...state,
        edges: state.edges.map((e) => (e.id === action.id ? { ...e, ...action.changes } : e)),
        isDirty: true,
      }

    case 'SELECT_EDGE':
      return {
        ...state,
        selectedEdgeId: action.id,
        selectedNodeId: null,
      }

    case 'DELETE_NODE':
      return {
        ...state,
        nodes: state.nodes.filter((n) => n.id !== action.id),
        edges: state.edges.filter((e) => e.sourceId !== action.id && e.targetId !== action.id),
        selectedNodeId: state.selectedNodeId === action.id ? null : state.selectedNodeId,
        pendingEdgeSourceId:
          state.pendingEdgeSourceId === action.id ? null : state.pendingEdgeSourceId,
        isDirty: true,
      }

    case 'DELETE_EDGE':
      return {
        ...state,
        edges: state.edges.filter((e) => e.id !== action.id),
        selectedEdgeId: state.selectedEdgeId === action.id ? null : state.selectedEdgeId,
        isDirty: true,
      }

    case 'MARK_SAVED':
      return {
        ...state,
        isDirty: false,
      }

    case 'RESTORE_SNAPSHOT':
      return {
        ...action.snapshot,
      }

    case 'SWITCH_FLOOR':
      return {
        ...state,
        nodes: action.nodes,
        edges: action.edges,
        activeFloorId: action.floorId,
        activeBuildingId: state.activeBuildingId,
        mode: 'select',
        selectedNodeId: null,
        selectedEdgeId: null,
        pendingEdgeSourceId: null,
        isDirty: false,
        // Cache the loaded floor data in snapshots
        floorSnapshots: {
          ...state.floorSnapshots,
          [action.floorId]: { nodes: action.nodes, edges: action.edges },
        },
      }

    case 'SWITCH_TO_CAMPUS':
      return {
        ...state,
        nodes: action.nodes,
        edges: action.edges,
        activeBuildingId: 'campus',
        activeFloorId: null,
        mode: 'select',
        selectedNodeId: null,
        selectedEdgeId: null,
        pendingEdgeSourceId: null,
        isDirty: false,
        campusSnapshot: { nodes: action.nodes, edges: action.edges },
      }

    case 'SWITCH_BUILDING':
      return {
        ...state,
        activeBuildingId: action.buildingId,
        activeFloorId: null,
        nodes: [],
        edges: [],
        mode: 'select',
        selectedNodeId: null,
        selectedEdgeId: null,
        pendingEdgeSourceId: null,
        isDirty: false,
      }

    default:
      return state
  }
}

// ============================================================
// ID Generation Helpers (exported)
// ============================================================

export function generateNodeId(type: string, label: string): string {
  const slug = label
    .toLowerCase()
    .replace(/\s+/g, '-')
    .replace(/[^a-z0-9-]/g, '')
  return `${type}-${slug || 'node'}-${Date.now()}`
}

export function generateEdgeId(sourceId: string, targetId: string): string {
  return `edge-${sourceId}-${targetId}-${Date.now()}`
}

// ============================================================
// Distance Calculation Helper (exported)
// ============================================================

export function calcDistance(a: { x: number; y: number }, b: { x: number; y: number }): number {
  return Math.sqrt((b.x - a.x) ** 2 + (b.y - a.y) ** 2)
}

// ============================================================
// Hook
// ============================================================

const MAX_HISTORY = 50

export function useEditorState() {
  const [state, dispatch] = useReducer(editorReducer, initialState)

  // Undo/redo refs — not React state to avoid unnecessary re-renders
  const history = useRef<EditorState[]>([initialState])
  const historyStep = useRef<number>(0)

  // Lightweight state to trigger re-renders when history position changes
  const [historyInfo, setHistoryInfo] = useState({ step: 0, length: 1 })

  const recordHistory = () => {
    // Discard redo future and push current state
    const newHistory = history.current.slice(0, historyStep.current + 1)
    newHistory.push(state)

    // Cap at MAX_HISTORY entries
    if (newHistory.length > MAX_HISTORY) {
      newHistory.shift()
    }

    history.current = newHistory
    historyStep.current = newHistory.length - 1

    setHistoryInfo({ step: historyStep.current, length: newHistory.length })
  }

  const handleUndo = () => {
    if (historyStep.current <= 0) return

    historyStep.current -= 1
    const snapshot = history.current[historyStep.current]
    if (!snapshot) return
    dispatch({ type: 'RESTORE_SNAPSHOT', snapshot })
    setHistoryInfo({ step: historyStep.current, length: history.current.length })
  }

  const handleRedo = () => {
    if (historyStep.current >= history.current.length - 1) return

    historyStep.current += 1
    const snapshot = history.current[historyStep.current]
    if (!snapshot) return
    dispatch({ type: 'RESTORE_SNAPSHOT', snapshot })
    setHistoryInfo({ step: historyStep.current, length: history.current.length })
  }

  const canUndo = historyInfo.step > 0
  const canRedo = historyInfo.step < historyInfo.length - 1

  const switchFloor = (floorId: number, nodes: NavNode[], edges: NavEdge[]) => {
    dispatch({ type: 'SWITCH_FLOOR', floorId, nodes, edges })
    // Reset undo history to the new floor's initial state
    const newState: EditorState = {
      ...initialState,
      activeBuildingId: state.activeBuildingId,
      activeFloorId: floorId,
      nodes,
      edges,
      floorSnapshots: { ...state.floorSnapshots, [floorId]: { nodes, edges } },
      campusSnapshot: state.campusSnapshot,
    }
    history.current = [newState]
    historyStep.current = 0
    setHistoryInfo({ step: 0, length: 1 })
  }

  const switchToCampus = (nodes: NavNode[], edges: NavEdge[]) => {
    dispatch({ type: 'SWITCH_TO_CAMPUS', nodes, edges })
    const newState: EditorState = {
      ...initialState,
      activeBuildingId: 'campus',
      activeFloorId: null,
      nodes,
      edges,
      campusSnapshot: { nodes, edges },
      floorSnapshots: state.floorSnapshots,
    }
    history.current = [newState]
    historyStep.current = 0
    setHistoryInfo({ step: 0, length: 1 })
  }

  return {
    state,
    dispatch,
    recordHistory,
    handleUndo,
    handleRedo,
    canUndo,
    canRedo,
    switchFloor,
    switchToCampus,
  }
}

